"use client"

import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { generateAISignal, AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { useUser, useFirestore } from '@/firebase';
import { collection, addDoc, serverTimestamp, doc, updateDoc, onSnapshot, increment } from 'firebase/firestore';
import { toast } from '@/hooks/use-toast';

export const useTradingSignals = () => {
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  
  const [loading, setLoading] = useState(false);
  const [signals, setSignals] = useState<Record<string, AISignalOutput | null>>({});
  const [profile, setProfile] = useState<any>(null);
  const [isSyncing, setIsSyncing] = useState(true);
  const [viewedSignalIds, setViewedSignalIds] = useState<Set<string>>(new Set());
  
  const lastHistoryIdsStrRef = useRef<string>("");
  const lastProfileStrRef = useRef<string>("");

  useEffect(() => {
    if (isUserLoading || !user || !db) {
      if (!isUserLoading && !user) setIsSyncing(false);
      return;
    }

    // Real-time profile sync
    const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
    const unsubscribeProfile = onSnapshot(profileRef, (snap) => {
      if (snap.exists()) {
        const data = snap.data();
        const dataStr = JSON.stringify(data);
        if (dataStr !== lastProfileStrRef.current) {
          setProfile(data);
          lastProfileStrRef.current = dataStr;
        }
      }
      setIsSyncing(false);
    }, (err) => {
      console.error("[PROFILE_SYNC] Error:", err);
      setIsSyncing(false);
    });

    // Real-time history sync to track which signals are already unlocked
    const historyRef = collection(db, 'users', user.uid, 'signalHistory');
    const unsubscribeHistory = onSnapshot(historyRef, (snap) => {
      const ids: string[] = [];
      snap.forEach(doc => {
        const data = doc.data();
        if (data.originalSignalId) ids.push(data.originalSignalId);
      });
      
      const currentIdsStr = JSON.stringify(ids.sort());
      if (currentIdsStr !== lastHistoryIdsStrRef.current) {
        setViewedSignalIds(new Set(ids));
        lastHistoryIdsStrRef.current = currentIdsStr;
      }
    });

    return () => {
      unsubscribeProfile();
      unsubscribeHistory();
    };
  }, [user?.uid, db, isUserLoading]);

  const adminEmails = useMemo(() => ['hassandeeb473@gmail.com', 'HassanDeeb@example.com'], []);
  
  const isVip = useMemo(() => {
    if (!profile) return false;
    return profile.isSubscribed === true || adminEmails.includes(user?.email || '');
  }, [profile, user?.email, adminEmails]);

  const signalsUsed = profile?.freeSignalsUsed || 0;

  // Function to unlock a signal and record it in user's history
  const unlockSignal = useCallback(async (signalId: string, signalData: any) => {
    if (!user || !db || !profile) return false;
    
    // If already unlocked, just return true
    if (viewedSignalIds.has(signalId)) return true;

    // Check limit for non-VIPs
    if (!isVip && signalsUsed >= 7) {
      toast({ 
        title: "VIP Access Required", 
        description: "Standard account limit reached (7 signals). Upgrade to continue.", 
        variant: "destructive" 
      });
      return false;
    }

    try {
      // 1. Increment usage if not VIP
      if (!isVip) {
        const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
        await updateDoc(profileRef, {
          freeSignalsUsed: increment(1),
          updatedAt: serverTimestamp()
        });
      }

      // 2. Generate a realistic pips result (60% win, 40% loss)
      const pipsResult = Math.random() > 0.4 
        ? (Math.floor(Math.random() * 45) + 12) // Win: 12-57 pips
        : -(Math.floor(Math.random() * 25) + 8); // Loss: 8-33 pips

      // 3. Add to user's execution log
      const historyRef = collection(db, 'users', user.uid, 'signalHistory');
      await addDoc(historyRef, {
        originalSignalId: signalId,
        symbol: signalData.asset || signalData.symbol,
        type: (signalData.asset || signalData.symbol || '').includes('/') ? 'Forex' : 'Crypto',
        direction: signalData.direction,
        entryPrice: signalData.entryPrice,
        takeProfit: signalData.takeProfit,
        stopLoss: signalData.stopLoss,
        lotSize: signalData.lotSize || 0.1,
        riskPercentage: signalData.riskPercentage || 1,
        confidenceScore: signalData.confidenceScore || 90,
        reasoning: signalData.reasoning || "Institutional setup.",
        viewedAt: serverTimestamp(),
        pipsResult: pipsResult
      });

      toast({ title: "Signal Unlocked", description: "This execution has been added to your log." });
      return true;
    } catch (e) {
      console.error("[UNLOCK_ERROR]", e);
      toast({ title: "Unlock Failed", variant: "destructive" });
      return false;
    }
  }, [user?.uid, db, profile, isVip, signalsUsed, viewedSignalIds]);

  const fetchSignal = useCallback(async (symbol: string, type: 'Forex' | 'Crypto') => {
    if (loading || !user || !db || !profile) return;
    
    // Check limit before even fetching
    if (!isVip && signalsUsed >= 7) {
      return 'limit_reached';
    }

    setLoading(true);
    try {
      const result = await generateAISignal({ instrumentName: symbol, instrumentType: type });
      setSignals(prev => ({ ...prev, [symbol]: result }));
      
      // Automatically unlock signals fetched via Pulse since user requested them specifically
      // Generate a temporary ID for tracking
      const tempId = `pulse-${symbol}-${Date.now()}`;
      await unlockSignal(tempId, result);
      
      return 'success';
    } catch (error) {
      console.error("[FETCH_SIGNAL_ERROR]", error);
      toast({ title: "Market Data Error", variant: "destructive" });
      return 'error';
    } finally {
      setLoading(false);
    }
  }, [user?.uid, db, loading, isVip, signalsUsed, profile, unlockSignal]);

  return {
    loading,
    signals,
    fetchSignal,
    unlockSignal,
    viewedSignalIds,
    profile,
    isSyncing,
    isVip,
    signalsUsed
  };
};