"use client"

import React, { useEffect, useRef, memo, useState } from 'react';
import { TrendingUp, TrendingDown, Lock, Eye, Activity, Scale, ShieldAlert, AlertTriangle } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { cn } from '@/lib/utils';

interface SignalCardProps {
  symbol: string;
  type: 'Forex' | 'Crypto';
  signal: AISignalOutput;
  isLocked?: boolean;
  onUnlock?: () => void;
  onUpgradeClick?: () => void;
}

export const SignalCard = memo(({ symbol, type, signal, isLocked, onUnlock, onUpgradeClick }: SignalCardProps) => {
  const isBuy = signal.direction === 'Buy';
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const [isWidgetLoading, setIsWidgetLoading] = useState(false);
  
  useEffect(() => {
    // Only load chart if not locked
    if (!chartContainerRef.current || isLocked) return;

    setIsWidgetLoading(true);
    const container = chartContainerRef.current;
    container.innerHTML = ""; 

    const widgetDiv = document.createElement("div");
    widgetDiv.className = "tradingview-widget-container__widget";
    widgetDiv.style.height = "100%";
    widgetDiv.style.width = "100%";
    container.appendChild(widgetDiv);

    const script = document.createElement("script");
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-mini-symbol-overview.js";
    script.type = "text/javascript";
    script.async = true;
    
    const cleanSym = symbol.toUpperCase().replace('/', '').replace('USDT', '').replace('USD', '');
    let tvSymbol = '';
    
    if (cleanSym === 'GOLD' || cleanSym === 'XAU') {
      tvSymbol = 'OANDA:XAUUSD';
    } else if (type === 'Crypto') {
      tvSymbol = `BINANCE:${cleanSym}USDT`;
    } else {
      tvSymbol = `FX:${cleanSym}USD`;
    }

    script.innerHTML = JSON.stringify({
      "symbol": tvSymbol,
      "width": "100%",
      "height": "100%",
      "locale": "en",
      "dateRange": "1D",
      "colorTheme": "dark",
      "trendLineColor": isBuy ? "#10b981" : "#ef4444",
      "underLineColor": isBuy ? "rgba(16, 185, 129, 0.1)" : "rgba(239, 68, 68, 0.1)",
      "underLineBottomColor": "rgba(41, 98, 255, 0)",
      "isTransparent": true,
      "autosize": true,
      "largeChartUrl": ""
    });
    
    script.onload = () => setIsWidgetLoading(false);
    container.appendChild(script);

    return () => {
      if (container) container.innerHTML = "";
    };
  }, [symbol, type, isLocked, isBuy]);
  
  return (
    <Card className={cn(
      "relative overflow-hidden border-white/5 bg-card/40 glassmorphism transition-all duration-300 rounded-3xl gpu-stable",
      "min-h-[520px] sm:min-h-[580px] h-full" 
    )}>
      <div className={cn(
        "absolute top-0 left-0 w-1.5 h-full z-20",
        isBuy ? 'bg-success shadow-[0_0_15px_rgba(16,185,129,0.5)]' : 'bg-destructive shadow-[0_0_15px_rgba(239,68,68,0.5)]'
      )} />
      
      <CardHeader className="flex flex-row items-center justify-between pb-4 p-5 sm:p-6 relative z-10 gap-2">
        <div className="space-y-1">
          <CardTitle className="text-xl sm:text-2xl font-black flex items-center gap-2 tracking-tighter uppercase">
            <span className="truncate max-w-[100px] sm:max-w-none">{symbol}</span>
            <Badge variant="outline" className="text-[8px] uppercase font-black bg-white/5 px-1.5 py-0 border-white/10 shrink-0">
              {type}
            </Badge>
          </CardTitle>
          <div className="flex items-center gap-1.5">
             <div className="w-1 h-1 rounded-full bg-success animate-pulse shrink-0" />
             <p className="text-[8px] text-muted-foreground/60 uppercase tracking-widest font-black truncate">Live WebSocket</p>
          </div>
        </div>
        {!isLocked && (
          <div className={cn(
            "flex items-center gap-1.5 font-black text-sm sm:text-xl tracking-tighter px-3 py-1 sm:px-4 sm:py-1.5 rounded-xl bg-white/5 border border-white/5 shrink-0",
            isBuy ? 'text-success neon-text-emerald' : 'text-destructive neon-text-crimson'
          )}>
            {isBuy ? <TrendingUp className="h-4 w-4 sm:h-5 sm:w-5" /> : <TrendingDown className="h-4 w-4 sm:h-5 sm:w-5" />}
            {signal.direction.toUpperCase()}
          </div>
        )}
      </CardHeader>

      <CardContent className="space-y-4 sm:space-y-5 p-5 sm:p-6 pt-0 relative h-full flex flex-col">
        {isLocked ? (
          <div className="absolute inset-0 z-50 flex flex-col items-center justify-center p-6 sm:p-8 text-center bg-black/90 backdrop-blur-3xl rounded-3xl animate-in fade-in duration-500">
            <div className="h-16 w-16 sm:h-20 sm:w-20 rounded-2xl sm:rounded-[2rem] bg-primary/10 border border-primary/20 flex items-center justify-center mb-4 sm:mb-6 shadow-xl">
              <Lock className="h-8 w-8 sm:h-10 sm:w-10 text-primary" />
            </div>
            <h3 className="text-lg sm:text-xl font-black uppercase tracking-tighter text-white mb-2">Signal Locked</h3>
            <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-6 sm:mb-8 leading-relaxed">
              Click unlock to calculate Pips results<br/>and add to your Execution Log
            </p>
            <div className="w-full space-y-3">
              <Button onClick={onUnlock} className="h-12 sm:h-14 w-full bg-primary text-black font-black uppercase text-xs sm:text-sm tracking-widest rounded-xl sm:rounded-2xl">
                <Eye className="h-4 w-4 sm:h-5 sm:w-5 mr-2" /> Unlock Signal
              </Button>
              <Button onClick={onUpgradeClick} variant="ghost" className="w-full text-amber-500 font-black uppercase text-[9px] tracking-[0.2em] h-8">
                Activate VIP for Unlimited
              </Button>
            </div>
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in-95 duration-500 space-y-4 sm:space-y-5 flex-1 flex flex-col">
            <div className="grid grid-cols-3 gap-2 sm:gap-3 p-4 sm:p-5 rounded-2xl bg-black/40 border border-white/5">
              <div className="space-y-1">
                <p className="text-[8px] text-muted-foreground uppercase font-black tracking-widest">Entry</p>
                <p className="text-[11px] sm:text-sm font-mono font-black text-white truncate">{signal.entryPrice.toLocaleString(undefined, { minimumFractionDigits: type === 'Crypto' ? 2 : 4 })}</p>
              </div>
              <div className="border-x border-white/5 px-2 sm:px-3 text-center space-y-1">
                <p className="text-[8px] text-accent uppercase font-black tracking-widest">TP</p>
                <p className="text-[11px] sm:text-sm font-mono font-black text-accent truncate">{signal.takeProfit.toLocaleString(undefined, { minimumFractionDigits: type === 'Crypto' ? 2 : 4 })}</p>
              </div>
              <div className="text-right space-y-1">
                <p className="text-[8px] text-destructive uppercase font-black tracking-widest">SL</p>
                <p className="text-[11px] sm:text-sm font-mono font-black text-destructive truncate">{signal.stopLoss.toLocaleString(undefined, { minimumFractionDigits: type === 'Crypto' ? 2 : 4 })}</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 sm:gap-3">
              <div className="p-3 rounded-xl bg-white/5 border border-white/5 flex items-center gap-2 sm:gap-3">
                <Scale className="h-4 w-4 text-primary shrink-0" />
                <div className="min-w-0">
                  <p className="text-[7px] sm:text-[8px] uppercase font-black text-muted-foreground truncate">Lot Size (1%)</p>
                  <p className="text-[10px] sm:text-xs font-bold truncate">{signal.lotSize.toFixed(2)}</p>
                </div>
              </div>
              <div className="p-3 rounded-xl bg-white/5 border border-white/5 flex items-center gap-2 sm:gap-3">
                <ShieldAlert className="h-4 w-4 text-amber-500 shrink-0" />
                <div className="min-w-0">
                  <p className="text-[7px] sm:text-[8px] uppercase font-black text-muted-foreground truncate">Confidence</p>
                  <p className="text-[10px] sm:text-xs font-bold truncate">{signal.confidenceScore}%</p>
                </div>
              </div>
            </div>

            <div className="h-40 sm:h-48 border border-white/5 rounded-2xl sm:rounded-3xl bg-black/40 overflow-hidden relative shadow-inner">
              <div ref={chartContainerRef} className="w-full h-full" />
              {isWidgetLoading && (
                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 backdrop-blur-md">
                  <Activity className="h-6 w-6 text-primary animate-spin mb-2" />
                  <p className="text-[7px] font-black text-muted-foreground uppercase tracking-widest">MAPPING CHART...</p>
                </div>
              )}
            </div>

            <div className="p-3 sm:p-4 rounded-xl sm:rounded-2xl bg-white/5 border border-white/10 space-y-3">
              <p className="text-[9px] sm:text-[10px] text-muted-foreground/90 leading-relaxed font-bold italic line-clamp-2">
                &ldquo;{signal.reasoning}&rdquo;
              </p>
              
              <div className="pt-2 border-t border-white/5 flex items-start gap-2">
                <AlertTriangle className="h-3 w-3 text-destructive shrink-0 mt-0.5" />
                <p className="text-[8px] sm:text-[9px] text-destructive/90 font-black uppercase leading-tight tracking-tight">
                  تنبيه: لا تأخذ هذه الصفقات بشكل حتمي ومؤكد لأنها مولدة بالذكاء الاصطناعي وغير دقيقة.
                </p>
              </div>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
});
SignalCard.displayName = 'SignalCard';