
"use client"

import React, { useState, useEffect, useCallback } from 'react';
import { ShieldCheck, BarChart2, Users, FilePlus2, Lock, Activity, Loader2, Search, Trash2, RefreshCcw, Clock, Award } from 'lucide-react';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogDescription 
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from '@/components/ui/badge';
import { toast } from '@/hooks/use-toast';
import { useFirestore, useCollection, useMemoFirebase, useUser } from '@/firebase';
import { collection, addDoc, serverTimestamp, query, getDocs, doc, updateDoc, deleteDoc, orderBy, limit, collectionGroup, writeBatch, where } from 'firebase/firestore';
import { generateAISignal } from '@/ai/flows/ai-signal-generation';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

export const AdminPanel = ({ isOpen, onClose }: AdminPanelProps) => {
  const db = useFirestore();
  const { user } = useUser();
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [loading, setLoading] = useState(false);
  const [broadcastLoading, setBroadcastLoading] = useState(false);
  const [userSearch, setUserSearch] = useState('');
  const [foundUsers, setFoundUsers] = useState<any[]>([]);
  const [searching, setSearching] = useState(false);
  const [countdown, setCountdown] = useState(600);

  // Manual Signal State
  const [asset, setAsset] = useState('');
  const [direction, setDirection] = useState<'Buy' | 'Sell'>('Buy');
  const [entry, setEntry] = useState('');
  const [tp, setTp] = useState('');
  const [sl, setSl] = useState('');
  const [reason, setReason] = useState('');

  const adminEmail = 'hassandeeb473@gmail.com';

  useEffect(() => {
    if (user?.email === adminEmail) {
      setIsAuthorized(true);
    } else {
      setIsAuthorized(false);
    }
  }, [user]);

  const manualSignalsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(collection(db, 'manualSignals'), orderBy('createdAt', 'desc'), limit(10));
  }, [db]);
  const { data: manualSignals } = useCollection(manualSignalsQuery);

  const handleManualBroadcast = async () => {
    if (!db || !asset || !entry || !tp || !sl) {
      toast({ title: "Required Fields Missing", variant: "destructive" });
      return;
    }
    setBroadcastLoading(true);
    try {
      await addDoc(collection(db, 'manualSignals'), {
        asset: asset.toUpperCase(),
        direction,
        entryPrice: parseFloat(entry),
        takeProfit: parseFloat(tp),
        stopLoss: parseFloat(sl),
        reasoning: reason || "Manual institutional analysis by Hassan Deeb.",
        confidenceScore: 100,
        lotSize: 0.1, // Default or calculated
        riskPercentage: 1,
        createdAt: serverTimestamp(),
      });
      toast({ title: "Manual Analysis Posted!" });
      setAsset(''); setEntry(''); setTp(''); setSl(''); setReason('');
    } finally {
      setBroadcastLoading(false);
    }
  };

  const deleteManualSignal = async (id: string) => {
    if (!db) return;
    await deleteDoc(doc(db, 'manualSignals', id));
    toast({ title: "Signal Removed" });
  };

  if (!isAuthorized && isOpen) {
    return (
      <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
        <DialogContent className="sm:max-w-md border-white/10 glassmorphism p-8">
          <div className="flex flex-col items-center text-center space-y-6">
            <div className="h-20 w-20 rounded-2xl bg-destructive/10 border border-destructive/30 flex items-center justify-center">
              <Lock className="h-10 w-10 text-destructive" />
            </div>
            <DialogHeader>
              <DialogTitle className="text-2xl font-black uppercase">Access Restricted</DialogTitle>
              <DialogDescription className="text-xs font-bold text-muted-foreground uppercase tracking-widest">
                Admin credentials required.
              </DialogDescription>
            </DialogHeader>
            <Button onClick={onClose} className="w-full h-14 bg-white/5 border border-white/10 rounded-xl font-black uppercase">Exit</Button>
          </div>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-7xl max-h-[95vh] overflow-y-auto border-white/10 glassmorphism p-0">
        <div className="p-10 space-y-10">
          <DialogHeader className="flex flex-row items-center justify-between">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <ShieldCheck className="h-6 w-6 text-primary" />
                <DialogTitle className="text-3xl font-black uppercase tracking-tighter">Hassan Deeb <span className="text-primary">Admin Terminal</span></DialogTitle>
              </div>
              <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-[0.3em]">Master Control Hub</p>
            </div>
          </DialogHeader>

          <Tabs defaultValue="manual" className="w-full">
            <TabsList className="grid w-full grid-cols-3 bg-white/5 border border-white/10 h-12 p-1 rounded-xl mb-8">
              <TabsTrigger value="manual" className="font-black uppercase text-[10px] tracking-widest">Post Manual Analysis</TabsTrigger>
              <TabsTrigger value="ai" className="font-black uppercase text-[10px] tracking-widest">AI Market Sync</TabsTrigger>
              <TabsTrigger value="users" className="font-black uppercase text-[10px] tracking-widest">Trader Hub</TabsTrigger>
            </TabsList>

            <TabsContent value="manual" className="space-y-10">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <Card className="bg-white/5 border-white/10 p-8 space-y-6 rounded-[2.5rem] shadow-none">
                  <h3 className="font-black text-xl uppercase tracking-tight flex items-center gap-2">
                    <Award className="h-6 w-6 text-amber-500" /> Hassan's Manual Setup
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">Symbol</label>
                      <Input value={asset} onChange={(e) => setAsset(e.target.value)} placeholder="GOLD or BTC/USD" className="bg-black/40 border-white/5 h-14 font-bold rounded-2xl" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">Direction</label>
                      <Select value={direction} onValueChange={(val: any) => setDirection(val)}>
                        <SelectTrigger className="bg-black/40 border-white/5 h-14 font-bold rounded-2xl"><SelectValue /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Buy">BUY</SelectItem>
                          <SelectItem value="Sell">SELL</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">Entry</label>
                      <Input value={entry} onChange={(e) => setEntry(e.target.value)} className="bg-black/40 border-white/5 h-14 rounded-2xl" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">TP</label>
                      <Input value={tp} onChange={(e) => setTp(e.target.value)} className="bg-black/40 border-white/5 h-14 rounded-2xl text-success" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">SL</label>
                      <Input value={sl} onChange={(e) => setSl(e.target.value)} className="bg-black/40 border-white/5 h-14 rounded-2xl text-destructive" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-muted-foreground ml-1">Note</label>
                      <Input value={reason} onChange={(e) => setReason(e.target.value)} placeholder="Technical reason..." className="bg-black/40 border-white/5 h-14 rounded-2xl" />
                    </div>
                  </div>
                  <Button onClick={handleManualBroadcast} disabled={broadcastLoading} className="w-full h-16 bg-amber-500 text-black font-black uppercase tracking-widest text-xs rounded-2xl shadow-lg shadow-amber-500/20">
                    {broadcastLoading ? <Loader2 className="h-6 w-6 animate-spin" /> : 'Broadcast to Manual Page'}
                  </Button>
                </Card>

                <Card className="bg-white/5 border-white/10 p-8 space-y-6 rounded-[2.5rem] shadow-none">
                  <h3 className="font-black text-xl uppercase tracking-tight">Active Manual Feed</h3>
                  <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                    {manualSignals?.map(sig => (
                      <div key={sig.id} className="p-5 rounded-3xl bg-black/40 border border-white/5 flex items-center justify-between group">
                        <div className="flex items-center gap-4">
                           <div className={cn("h-12 w-12 rounded-2xl flex items-center justify-center", sig.direction === 'Buy' ? 'bg-success/10' : 'bg-destructive/10')}>
                              <BarChart2 className={cn("h-6 w-6", sig.direction === 'Buy' ? 'text-success' : 'text-destructive')} />
                           </div>
                           <div>
                              <p className="font-black text-base uppercase tracking-tighter">{sig.asset}</p>
                              <p className="text-[10px] text-muted-foreground uppercase font-black">Manual: {sig.direction} @ {sig.entryPrice}</p>
                           </div>
                        </div>
                        <Button variant="ghost" size="icon" onClick={() => deleteManualSignal(sig.id)} className="text-destructive hover:bg-destructive/10">
                          <Trash2 className="h-5 w-5" />
                        </Button>
                      </div>
                    ))}
                  </div>
                </Card>
              </div>
            </TabsContent>
            
            {/* ... Other Tabs (AI, Users) remain same or simplified ... */}
            <TabsContent value="ai">
               <div className="py-20 text-center">
                  <p className="text-sm font-black uppercase text-muted-foreground">AI Auto-Seeding is currently active.</p>
                  <p className="text-[10px] text-muted-foreground/50 mt-2">Update intervals: 10 minutes.</p>
               </div>
            </TabsContent>

            <TabsContent value="users" className="space-y-8">
              <div className="flex gap-4 p-6 bg-white/5 rounded-3xl border border-white/5">
                <div className="relative flex-1">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input placeholder="Trader Email..." value={userSearch} onChange={(e) => setUserSearch(e.target.value)} className="bg-black/40 h-14 pl-12 border-white/10 font-bold rounded-2xl" />
                </div>
                <Button onClick={() => {}} className="bg-primary text-black font-black uppercase px-10 h-14 rounded-2xl">
                  Identify Account
                </Button>
              </div>
            </TabsContent>
          </Tabs>
        </div>
      </DialogContent>
    </Dialog>
  );
};
